    fprintf(fp, "      \"heap_sig\": %zu,\n", res->heap_sig);
    fprintf(fp, "      \"fl_count\": %d,\n", res->fl_count);
    fprintf(fp, "      \"fl_sig\": %zu,\n", res->fl_sig);
    fprintf(fp, "      \"byte_total\": %zu,\n", res->byte_total);
    fprintf(fp, "      \"ledger\": ");
