    a->slots[idx] = fit->base + fit->off + HDR_SIZE;
    a->slot_payload[idx] = req;
    a->slot_live[idx] = 1;
    a->stats.live_blocks++;
    memset(a->slots[idx], (unsigned char)(idx + 1), req < 64 ? req : 64);
